import React, { useState } from "react";

import "./App.css";

import Sidebar from "./components/Sidebar";

import Dashboard from "./components/Dashboard";

/* Pages */

import AIAssistant from "./pages/AIAssistant";
import Weather from "./pages/Weather";
import CropAdvisor from "./pages/CropAdvisor";
import MarketPrices from "./pages/MarketPrices";
import Schemes from "./pages/Schemes";
import News from "./pages/News";
import Maps from "./pages/Maps";
import Reports from "./pages/Reports";
import Tasks from "./pages/Tasks";
import Finance from "./pages/Finance";
import FarmRecords from "./pages/FarmRecords";
import Inventory from "./pages/Inventory";
import Complaints from "./pages/Complaints";
import Calendar from "./pages/Calendar";
import Profile from "./pages/Profile";
import Settings from "./pages/Settings";
import HelpSupport from "./pages/HelpSupport";

function App() {

const [activePage,setActivePage]=useState("Dashboard");

const [language,setLanguage]=useState("en");

const renderPage=()=>{

switch(activePage){

case "Dashboard":

return (

<Dashboard

setActivePage={setActivePage}

language={language}

/>

);

case "AI Assistant":

return <AIAssistant language={language}/>;


case "Weather":

return <Weather language={language}/>;


case "Crop Advisor":

return <CropAdvisor language={language}/>;


case "Market Prices":

return <MarketPrices language={language}/>;


case "Schemes":

return <Schemes language={language}/>;


case "News":

return <News language={language}/>;


case "Maps":

return <Maps language={language}/>;


case "Reports":

return <Reports language={language}/>;


case "Tasks":

return <Tasks language={language}/>;


case "Finance":

return <Finance language={language}/>;


case "Farm Records":

return <FarmRecords language={language}/>;


case "Inventory":

return <Inventory language={language}/>;


case "Complaints":

return <Complaints language={language}/>;


case "Calendar":

return <Calendar language={language}/>;


case "Profile":

return <Profile language={language}/>;


case "Settings":

return <Settings language={language}/>;


case "Help Support":

return <HelpSupport language={language}/>;


default:

return (

<Dashboard

setActivePage={setActivePage}

language={language}

/>

);

}

};

return(

<div className="app-container">

<Sidebar

activePage={activePage}

setActivePage={setActivePage}

language={language}

setLanguage={setLanguage}

/>

<div className="main-container">

{renderPage()}

</div>

</div>

);

}

export default App;
